__global__ void floydWarshallKernel(unsigned int *pathDistanceMatrix,
                                    unsigned int *pathMatrix,
                                    unsigned int numNodes,
                                    unsigned int k)
{
  unsigned long long idx = (unsigned long long)blockIdx.x * blockDim.x + threadIdx.x;
  unsigned long long stride = (unsigned long long)blockDim.x * gridDim.x;
  unsigned long long total = (unsigned long long)numNodes * (unsigned long long)numNodes;

  for (; idx < total; idx += stride)
  {
    unsigned int y = (unsigned int)(idx / numNodes);
    unsigned int x = (unsigned int)(idx - (unsigned long long)y * numNodes);

    unsigned int distanceYtoX = pathDistanceMatrix[(unsigned long long)y * numNodes + x];
    unsigned int distanceYtoK = pathDistanceMatrix[(unsigned long long)y * numNodes + k];
    unsigned int distanceKtoX = pathDistanceMatrix[(unsigned long long)k * numNodes + x];
    unsigned int indirectDistance = distanceYtoK + distanceKtoX;

    if(indirectDistance < distanceYtoX)
    {
      pathDistanceMatrix[(unsigned long long)y * numNodes + x] = indirectDistance;
      pathMatrix[(unsigned long long)y * numNodes + x]         = k;
    }
  }
}

