int main(int argc, char *argv[]) {

  if (argc != 4) {
    usage(argv);
    exit(1);
  }

  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 || Ly % NTY != 0) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
           NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);

  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f + 4.0f * sigma);
  const float xnorm = 1.0f / (1.0f + 4.0f * sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);

  srand(123);
  float *buffer = (float *)malloc(sizeof(float) * Lx * Ly);
  float *h_out = (float *)malloc(sizeof(float) * Lx * Ly);
  float *h_in  = (float *)malloc(sizeof(float) * Lx * Ly);

  int i, j, x, y;
  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; j < Ly; j++)
      buffer[x + j * Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; j < Lx; j++)
      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float) * Lx * Ly);

  for (i = 0; i < niter; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    float *tmp = h_out;
    h_out = h_in;
    h_in = tmp;
  }

  float *d_out = (float *)malloc(sizeof(float) * Lx * Ly);
  float *d_in  = (float *)malloc(sizeof(float) * Lx * Ly);
  memcpy(d_in, buffer, sizeof(float) * Lx * Ly);

  float *dev_out = NULL;
  float *dev_in = NULL;
  CUDA_CHECK(cudaMalloc((void **)&dev_out, sizeof(float) * Lx * Ly));
  CUDA_CHECK(cudaMalloc((void **)&dev_in, sizeof(float) * Lx * Ly));
  CUDA_CHECK(cudaMemcpy(dev_in, d_in, sizeof(float) * Lx * Ly, cudaMemcpyHostToDevice));

  double t0;
  dim3 block(NTX, NTY);
  dim3 grid(Lx / NTX, Ly / NTY);

  cudaEvent_t start, stop;
  CUDA_CHECK(cudaEventCreate(&start));
  CUDA_CHECK(cudaEventCreate(&stop));

  CUDA_CHECK(cudaEventRecord(start));
  for (i = 0; i < niter; i++) {
    dev_lapl_iter_kernel<<<grid, block>>>(dev_out, dev_in, xdelta, xnorm, Lx, Ly);
    CUDA_CHECK(cudaGetLastError());

    float *tmp_dev = dev_out;
    dev_out = dev_in;
    dev_in = tmp_dev;

    float *tmp_host = d_out;
    d_out = d_in;
    d_in = tmp_host;
  }
  CUDA_CHECK(cudaEventRecord(stop));
  CUDA_CHECK(cudaEventSynchronize(stop));

  float elapsed_ms = 0.0f;
  CUDA_CHECK(cudaEventElapsedTime(&elapsed_ms, start, stop));
  t0 = (double)elapsed_ms * 1000.0 / (double)niter;

  CUDA_CHECK(cudaMemcpy(d_in, dev_in, sizeof(float) * Lx * Ly, cudaMemcpyDeviceToHost));

  CUDA_CHECK(cudaEventDestroy(start));
  CUDA_CHECK(cudaEventDestroy(stop));
  CUDA_CHECK(cudaFree(dev_in));
  CUDA_CHECK(cudaFree(dev_out));

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
         niter, Lx, Ly, t0,
         Lx * Ly * sizeof(float) * 2.0 / (t0 * 1.0e3),
         (Lx * Ly * 6.0) / (t0 * 1.0e3));

  bool ok = true;
  for (i = 0; i < Lx * Ly; i++) {
    if (fabs(h_in[i] - d_in[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_in[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(buffer);
  free(h_out);
  free(h_in);
  free(d_in);
  free(d_out);
  return 0;
}

