void initialize(float* ptr_prev, float* ptr_next, float* ptr_vel, size_t nRows,
                size_t nCols) {
  std::cout << "Initializing ... " << std::endl;

  float wavelet[12] = {0.016387336f, -0.041464937f, -0.067372555f, 0.386110067f,
