                       0.023680172f, 0.005611435f,  0.001823209f,  -0.000720549f};

  for (size_t i = 0; nRows > i; i++) {
    size_t offset = i * nCols;

    for (size_t k = 0; k < nCols; k++) {
      ptr_prev[offset + k] = 0.0f;
