      }
      if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
      if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
      if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
      if (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
      if (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
      if (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
      if (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

      thread_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
    }
#endif
  }

  sdata[threadIdx.x] = thread_sum;
  __syncthreads();

  for (unsigned int s = BLOCK_SIZE / 2; s > 0; s >>= 1) {
    if (threadIdx.x < s) {
      sdata[threadIdx.x] += sdata[threadIdx.x + s];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    atomic_add_compat(global_sum, sdata[0]);
  }
}

template <typename T, unsigned int compute_iterations>
void bench_device(size_t len, T* d_src, void* d_sum_bytes, int grid_size) {
  T* d_sum = reinterpret_cast<T*>(d_sum_bytes);
  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(T)));
  bench_kernel<T, compute_iterations, kBlockSize>
      <<<grid_size, kBlockSize>>>(d_src, len, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(
      cudaMemcpyAsync(d_src, d_sum, sizeof(T), cudaMemcpyDeviceToDevice));
}

template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, start, stop));
  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));
  return static_cast<double>(ms);
}

template <typename Op>
double benchmark_gpu(Op op) {
  constexpr int total_runs = 20;

  (void)op();
  std::vector<double> measurements;
  measurements.reserve(total_runs - 1);

  for (int i = 1; i < total_runs; ++i) {
    measurements.push_back(op());
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t data_0, int compute_iterations)
      : memory_space_{data_0}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

static int choose_grid_size(size_t len) {
  size_t num_chunks = (len + kStaticChunkSize - 1) / kStaticChunkSize;
  cudaDeviceProp prop;
  int dev = 0;
  CUDA_SAFE_CALL(cudaGetDevice(&dev));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, dev));
  int grid = prop.multiProcessorCount * 32;
  if (grid < 1) grid = 1;
  if (num_chunks > 0 && static_cast<size_t>(grid) > num_chunks) {
    grid = static_cast<int>(num_chunks);
  }
  if (grid < 1) grid = 1;
  return grid;
}

double runbench_warmup(void* d_data, size_t size_bytes, void* d_sum_bytes) {
  const size_t num_elements = size_bytes / sizeof(double);
  const int grid_size = choose_grid_size(num_elements);
  return measure_operation([&] {
    bench_device<double, 16>(num_elements, reinterpret_cast<double*>(d_data),
                             d_sum_bytes, grid_size);
  });
}

