struct ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

inline int get_sm_count() {
  int device = 0;
  cudaDeviceProp prop{};
  CUDA_SAFE_CALL(cudaGetDevice(&device));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, device));
  return prop.multiProcessorCount;
}

inline int choose_block_count(size_t len) {
  const size_t blocks_by_len =
      (len + static_cast<size_t>(kThreadsPerBlock) - 1) / kThreadsPerBlock;
  const size_t preferred = static_cast<size_t>(get_sm_count()) * 32;
  size_t blocks = std::min(blocks_by_len, preferred);
  if (blocks == 0) blocks = 1;
  if (blocks > 65535) blocks = 65535;
  return static_cast<int>(blocks);
}

template <typename T, unsigned int compute_iterations>
__global__ void bench_kernel(const T* data, size_t len, T* block_sums) {
  extern __shared__ unsigned char smem_raw[];
  T* sdata = reinterpret_cast<T*>(smem_raw);

  const unsigned int tid = threadIdx.x;
  const size_t global_idx =
      static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  const size_t stride = static_cast<size_t>(blockDim.x) * gridDim.x;

  T sum = static_cast<T>(0);

#ifdef BASELINE_IMPL
  for (size_t i = global_idx; i < len; i += stride) {
    const size_t chunk_base = (i / kStaticChunkSize) * kStaticChunkSize;
    const T f = data[chunk_base];
    T t = data[i];
#pragma unroll
    for (unsigned int j = 0; j < compute_iterations; ++j) {
      t = t * t + f;
    }
    sum += t;
  }
#else
  for (size_t i = global_idx; i < len; i += stride) {
    const size_t chunk_base = (i / kStaticChunkSize) * kStaticChunkSize;

    const T f0 = data[chunk_base + 0];
    const T f1 = data[chunk_base + 1];
    const T f2 = data[chunk_base + 2];
    const T f3 = data[chunk_base + 3];
    const T f4 = data[chunk_base + 4];
    const T f5 = data[chunk_base + 5];
    const T f6 = data[chunk_base + 6];
    const T f7 = data[chunk_base + 7];

    const T d = data[i];
    T t0 = d, t1 = d, t2 = d, t3 = d, t4 = d, t5 = d, t6 = d, t7 = d;

#pragma unroll
    for (unsigned int j = 0; j < compute_iterations / 8; ++j) {
      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }

    if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
    if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
    if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
    if (3 < compute_iterations % 8) t3 = t3 * t3 + f3;
    if (4 < compute_iterations % 8) t4 = t4 * t4 + f4;
    if (5 < compute_iterations % 8) t5 = t5 * t5 + f5;
    if (6 < compute_iterations % 8) t6 = t6 * t6 + f6;

    sum += t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
  }
#endif

  sdata[tid] = sum;
  __syncthreads();

  for (unsigned int s = blockDim.x >> 1; s > 0; s >>= 1) {
    if (tid < s) {
      sdata[tid] += sdata[tid + s];
    }
    __syncthreads();
  }

  if (tid == 0) {
    block_sums[blockIdx.x] = sdata[0];
  }
}

template <typename T, unsigned int compute_iterations>
void launch_bench(T* d_data, size_t len, T* d_block_sums, int blocks) {
  bench_kernel<T, compute_iterations>
      <<<blocks, kThreadsPerBlock, kThreadsPerBlock * sizeof(T)>>>(
          d_data, len, d_block_sums);
  CUDA_SAFE_CALL(cudaGetLastError());
}

template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, start, stop));

  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));
  return static_cast<double>(ms);
}

template <typename Op>
double benchmark_cuda(int full_blocks, Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  op(full_blocks);
  std::vector<double> measurements;

  for (int i = 1; i < total_runs; i++) {
    measurements.push_back(op(full_blocks));
  }

  if (full_blocks > 1) {
    const int half_blocks = std::max(1, full_blocks / 2);
    for (int i = 1; i < total_half_thread_runs; i++) {
      measurements.push_back(op(half_blocks));
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

void runbench_warmup(void* d_buffer, size_t size_bytes) {
  const size_t num_elements = size_bytes / sizeof(double);
  const int blocks = choose_block_count(num_elements);

  double* d_block_sums = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_block_sums, static_cast<size_t>(blocks) * sizeof(double)));

  launch_bench<double, 16>(reinterpret_cast<double*>(d_buffer), num_elements,
                           d_block_sums, blocks);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  CUDA_SAFE_CALL(cudaFree(d_block_sums));
}

template <unsigned int compute_iterations>
void runbench(void* d_buffer, size_t size_bytes) {
  ComputeSpace cs{size_bytes, static_cast<int>(compute_iterations)};

  float* d_block_sums_float = nullptr;
  double* d_block_sums_double = nullptr;
  int* d_block_sums_int = nullptr;

  const size_t float_len = cs.element_count<float>();
  const size_t double_len = cs.element_count<double>();
  const size_t int_len = cs.element_count<int>();

  const int float_blocks = choose_block_count(float_len);
  const int double_blocks = choose_block_count(double_len);
  const int int_blocks = choose_block_count(int_len);

  CUDA_SAFE_CALL(
      cudaMalloc(&d_block_sums_float, static_cast<size_t>(float_blocks) * sizeof(float)));
  CUDA_SAFE_CALL(cudaMalloc(&d_block_sums_double,
                            static_cast<size_t>(double_blocks) * sizeof(double)));
  CUDA_SAFE_CALL(
      cudaMalloc(&d_block_sums_int, static_cast<size_t>(int_blocks) * sizeof(int)));

  float* c_as_float = reinterpret_cast<float*>(d_buffer);
  const auto kernel_time_mad_sp = benchmark_cuda(float_blocks, [&](int blocks) {
    return measure_operation([&] {
      launch_bench<float, compute_iterations>(c_as_float, float_len,
                                              d_block_sums_float, blocks);
    });
  });

  double* c_as_double = reinterpret_cast<double*>(d_buffer);
  const auto kernel_time_mad_dp = benchmark_cuda(double_blocks, [&](int blocks) {
    return measure_operation([&] {
      launch_bench<double, compute_iterations>(c_as_double, double_len,
                                               d_block_sums_double, blocks);
    });
  });

  int* c_as_int = reinterpret_cast<int*>(d_buffer);
  const auto kernel_time_mad_int = benchmark_cuda(int_blocks, [&](int blocks) {
    return measure_operation([&] {
      launch_bench<int, compute_iterations>(c_as_int, int_len, d_block_sums_int,
                                            blocks);
    });
  });

  CUDA_SAFE_CALL(cudaFree(d_block_sums_float));
  CUDA_SAFE_CALL(cudaFree(d_block_sums_double));
  CUDA_SAFE_CALL(cudaFree(d_block_sums_int));

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* d_buffer, size_t size_bytes) {
