static constexpr size_t kStaticChunkSize = 4096;
static constexpr int kDefaultThreads = 256;
static constexpr int kTotalRuns = 20;
static constexpr int kTotalHalfThreadRuns = 10;

template <typename T>
__device__ __forceinline__ T atomicAddCompat(T* address, T val);

template <>
__device__ __forceinline__ float atomicAddCompat<float>(float* address,
                                                        float val) {
  return atomicAdd(address, val);
}

template <>
__device__ __forceinline__ int atomicAddCompat<int>(int* address, int val) {
  return atomicAdd(address, val);
}

template <>
__device__ __forceinline__ double atomicAddCompat<double>(double* address,
                                                          double val) {
#if __CUDA_ARCH__ >= 600
  return atomicAdd(address, val);
#else
  unsigned long long int* address_as_ull =
      reinterpret_cast<unsigned long long int*>(address);
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val +
                                         __longlong_as_double(assumed)));
  } while (assumed != old);
  return __longlong_as_double(old);
#endif
}

template <typename Element>
__global__ void init_zero_kernel(Element* data, size_t len) {
  size_t idx = static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  size_t stride = static_cast<size_t>(gridDim.x) * blockDim.x;
  for (size_t i = idx; i < len; i += stride) {
    data[i] = 0;
  }
}

#ifdef BASELINE_IMPL

template <typename Element, unsigned int compute_iterations>
__device__ __noinline__ Element bench_block(Element* data, size_t count) {
  Element sum = 0;
  Element f = data[0];

  for (size_t i = 0; i < count; i++) {
    Element t = data[i];
#pragma unroll
    for (unsigned int j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }
  return sum;
}

#else

template <typename Element, unsigned int compute_iterations>
__device__ __noinline__ Element bench_block(Element* data, size_t count) {
  Element sum = 0;

  Element f[8];
  f[0] = data[0];
  f[1] = (count > 1) ? data[1] : data[0];
  f[2] = (count > 2) ? data[2] : data[0];
  f[3] = (count > 3) ? data[3] : data[0];
  f[4] = (count > 4) ? data[4] : data[0];
  f[5] = (count > 5) ? data[5] : data[0];
  f[6] = (count > 6) ? data[6] : data[0];
  f[7] = (count > 7) ? data[7] : data[0];

  for (size_t i = 0; i < count; i++) {
    Element t[8] = {data[i], data[i], data[i], data[i],
                    data[i], data[i], data[i], data[i]};

#pragma unroll
    for (unsigned int j = 0; j < compute_iterations / 8; j++) {
      t[0] = t[0] * t[0] + f[0];
      t[1] = t[1] * t[1] + f[1];
      t[2] = t[2] * t[2] + f[2];
      t[3] = t[3] * t[3] + f[3];
      t[4] = t[4] * t[4] + f[4];
      t[5] = t[5] * t[5] + f[5];
      t[6] = t[6] * t[6] + f[6];
      t[7] = t[7] * t[7] + f[7];
    }
    if ((compute_iterations % 8) > 0) {
      t[0] = t[0] * t[0] + f[0];
    }
    if ((compute_iterations % 8) > 1) {
      t[1] = t[1] * t[1] + f[1];
    }
    if ((compute_iterations % 8) > 2) {
      t[2] = t[2] * t[2] + f[2];
    }
    if ((compute_iterations % 8) > 3) {
      t[3] = t[3] * t[3] + f[3];
    }
    if ((compute_iterations % 8) > 4) {
      t[4] = t[4] * t[4] + f[4];
    }
    if ((compute_iterations % 8) > 5) {
      t[5] = t[5] * t[5] + f[5];
    }
    if ((compute_iterations % 8) > 6) {
      t[6] = t[6] * t[6] + f[6];
    }
    sum += t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];
  }
  return sum;
}

#endif

template <typename Element, unsigned int compute_iterations>
__global__ void bench_kernel(size_t len, Element* src, Element* sum_out) {
  size_t tid = static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  size_t stride = static_cast<size_t>(gridDim.x) * blockDim.x;

  Element local_sum = 0;

  for (size_t chunk_idx = tid;; chunk_idx += stride) {
    size_t it_base = chunk_idx * kStaticChunkSize;
    if (it_base >= len) break;
    size_t count = len - it_base;
    if (count > kStaticChunkSize) count = kStaticChunkSize;
    local_sum += bench_block<Element, compute_iterations>(src + it_base, count);
  }

  atomicAddCompat(sum_out, local_sum);
}

static int get_sm_count() {
  int sm_count = 1;
  CUDA_SAFE_CALL(cudaDeviceGetAttribute(&sm_count, cudaDevAttrMultiProcessorCount, 0));
  return sm_count;
}

static int choose_blocks(size_t len) {
  size_t chunk_count = (len + kStaticChunkSize - 1) / kStaticChunkSize;
  if (chunk_count == 0) return 1;

  const int sm_count = get_sm_count();
  const int max_blocks = std::max(1, sm_count * 32);
  size_t needed_blocks = (chunk_count + kDefaultThreads - 1) / kDefaultThreads;
  if (needed_blocks == 0) needed_blocks = 1;
  if (needed_blocks > static_cast<size_t>(max_blocks)) needed_blocks = max_blocks;
  return static_cast<int>(needed_blocks);
}

template <typename Element, unsigned int compute_iterations>
double launch_bench(size_t len, Element* src, Element* d_sum, int blocks,
                    int threads) {
  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));

  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start));
  bench_kernel<Element, compute_iterations><<<blocks, threads>>>(len, src, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(cudaMemcpyAsync(src, d_sum, sizeof(Element),
                                 cudaMemcpyDeviceToDevice));
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float elapsed_ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed_ms, start, stop));

  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));

  return static_cast<double>(elapsed_ms);
}

template <typename OpFull, typename OpHalf>
double benchmark_cuda(OpFull op_full, OpHalf op_half, bool has_half) {
  auto duration = op_full();
  std::vector<double> measurements;

  for (int i = 1; i < kTotalRuns; i++) {
    duration = op_full();
    measurements.push_back(duration);
  }

  if (has_half) {
    for (int i = 1; i < kTotalHalfThreadRuns; i++) {
      duration = op_half();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_(memory_space), compute_iterations_(compute_iterations) {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

static double runbench_warmup(void* d_buffer, size_t size_bytes) {
  size_t count = size_bytes / sizeof(double);
  double* d_ptr = reinterpret_cast<double*>(d_buffer);

  double* d_sum = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_sum, sizeof(double)));
  double elapsed = launch_bench<double, 16>(count, d_ptr, d_sum,
                                            choose_blocks(count),
                                            kDefaultThreads);
  CUDA_SAFE_CALL(cudaFree(d_sum));
  return elapsed;
}

template <unsigned int compute_iterations>
void runbench(void* d_buffer, size_t size_bytes) {
  ComputeSpace cs(size_bytes, static_cast<int>(compute_iterations));

  float* d_float = reinterpret_cast<float*>(d_buffer);
  float* d_sum_float = nullptr;
