            kDefaultThreads);
      },
      [&] {
        return launch_bench<float, compute_iterations>(
            cs.element_count<float>(), d_float, d_sum_float, half_blocks_sp,
            kDefaultThreads);
      },
      full_blocks_sp > 1);
  CUDA_SAFE_CALL(cudaFree(d_sum_float));

  double* d_double = reinterpret_cast<double*>(d_buffer);
  double* d_sum_double = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_double, sizeof(double)));
  int full_blocks_dp = choose_blocks(cs.element_count<double>());
  int half_blocks_dp = std::max(1, full_blocks_dp / 2);
  auto kernel_time_mad_dp = benchmark_cuda(
      [&] {
        return launch_bench<double, compute_iterations>(
            cs.element_count<double>(), d_double, d_sum_double, full_blocks_dp,
            kDefaultThreads);
      },
      [&] {
        return launch_bench<double, compute_iterations>(
