      },
      full_blocks_dp > 1);
  CUDA_SAFE_CALL(cudaFree(d_sum_double));

  int* d_int = reinterpret_cast<int*>(d_buffer);
  int* d_sum_int = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_sum_int, sizeof(int)));
  int full_blocks_int = choose_blocks(cs.element_count<int>());
  int half_blocks_int = std::max(1, full_blocks_int / 2);
  auto kernel_time_mad_int = benchmark_cuda(
      [&] {
        return launch_bench<int, compute_iterations>(
            cs.element_count<int>(), d_int, d_sum_int, full_blocks_int,
            kDefaultThreads);
      },
      [&] {
        return launch_bench<int, compute_iterations>(
            cs.element_count<int>(), d_int, d_sum_int, half_blocks_int,
            kDefaultThreads);
      },
      full_blocks_int > 1);
  CUDA_SAFE_CALL(cudaFree(d_sum_int));

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
