    const int *graph_visited,
    int *cost)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < no_of_nodes && graph_mask[tid] == 1) {
        graph_mask[tid] = 0;
        int edge_start = graph_nodes[tid].starting;
        int edge_end = edge_start + graph_nodes[tid].no_of_edges;
        int next_cost = cost[tid] + 1;

        for (int i = edge_start; i < edge_end; i++) {
            int id = graph_edges[i];
            if (graph_visited[id] == 0) {
                if (atomicCAS(&updating_graph_mask[id], 0, 1) == 0) {
                    cost[id] = next_cost;
                }
            }
        }
    }
}

