long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6)

#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP 0.5
#define OPEN

typedef float FLOAT;

const FLOAT t_chip = 0.0005f;
const FLOAT chip_height = 0.016f;
const FLOAT chip_width = 0.016f;
const FLOAT amb_temp = 80.0f;

int num_omp_threads;

static void cuda_check(cudaError_t err, const char *msg)
{
    if (err != cudaSuccess) {
        fprintf(stderr, "error: %s: %s\n", msg, cudaGetErrorString(err));
        exit(1);
    }
}

__global__ void single_iteration_kernel(FLOAT *result, const FLOAT *temp, const FLOAT *power, int row, int col,
                                        FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1,
                                        FLOAT step)
{
    FLOAT delta;
    int r, c;
    int chunk = blockIdx.x * blockDim.x + threadIdx.x;
    int num_chunk = row * col / (BLOCK_SIZE_R * BLOCK_SIZE_C);
    int chunks_in_row = col / BLOCK_SIZE_C;
    int chunks_in_col = row / BLOCK_SIZE_R;

    if (chunk >= num_chunk)
        return;

    int r_start = BLOCK_SIZE_R * (chunk / chunks_in_col);
    int c_start = BLOCK_SIZE_C * (chunk % chunks_in_row);
    int r_end = r_start + BLOCK_SIZE_R > row ? row : r_start + BLOCK_SIZE_R;
    int c_end = c_start + BLOCK_SIZE_C > col ? col : c_start + BLOCK_SIZE_C;

    if (r_start == 0 || c_start == 0 || r_end == row || c_end == col)
    {
        for (r = r_start; r < r_start + BLOCK_SIZE_R; ++r) {
            for (c = c_start; c < c_start + BLOCK_SIZE_C; ++c) {

                if ((r == 0) && (c == 0)) {
                    delta = (Cap_1) * (power[0] +
                        (temp[1] - temp[0]) * Rx_1 +
                        (temp[col] - temp[0]) * Ry_1 +
                        (amb_temp - temp[0]) * Rz_1);
                }
                else if ((r == 0) && (c == col - 1)) {
                    delta = (Cap_1) * (power[c] +
                        (temp[c - 1] - temp[c]) * Rx_1 +
                        (temp[c + col] - temp[c]) * Ry_1 +
                        (amb_temp - temp[c]) * Rz_1);
                }
                else if ((r == row - 1) && (c == col - 1)) {
                    delta = (Cap_1) * (power[r * col + c] +
                        (temp[r * col + c - 1] - temp[r * col + c]) * Rx_1 +
                        (temp[(r - 1) * col + c] - temp[r * col + c]) * Ry_1 +
                        (amb_temp - temp[r * col + c]) * Rz_1);
                }
                else if ((r == row - 1) && (c == 0)) {
                    delta = (Cap_1) * (power[r * col] +
                        (temp[r * col + 1] - temp[r * col]) * Rx_1 +
                        (temp[(r - 1) * col] - temp[r * col]) * Ry_1 +
                        (amb_temp - temp[r * col]) * Rz_1);
                }
                else if (r == 0) {
                    delta = (Cap_1) * (power[c] +
                        (temp[c + 1] + temp[c - 1] - 2.0f * temp[c]) * Rx_1 +
                        (temp[col + c] - temp[c]) * Ry_1 +
                        (amb_temp - temp[c]) * Rz_1);
                }
                else if (c == col - 1) {
                    delta = (Cap_1) * (power[r * col + c] +
                        (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[r * col + c]) * Ry_1 +
                        (temp[r * col + c - 1] - temp[r * col + c]) * Rx_1 +
                        (amb_temp - temp[r * col + c]) * Rz_1);
                }
                else if (r == row - 1) {
                    delta = (Cap_1) * (power[r * col + c] +
                        (temp[r * col + c + 1] + temp[r * col + c - 1] - 2.0f * temp[r * col + c]) * Rx_1 +
                        (temp[(r - 1) * col + c] - temp[r * col + c]) * Ry_1 +
                        (amb_temp - temp[r * col + c]) * Rz_1);
                }
                else if (c == 0) {
                    delta = (Cap_1) * (power[r * col] +
                        (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[r * col]) * Ry_1 +
                        (temp[r * col + 1] - temp[r * col]) * Rx_1 +
                        (amb_temp - temp[r * col]) * Rz_1);
                }
                result[r * col + c] = temp[r * col + c] + delta;
            }
        }
        return;
    }

    for (r = r_start; r < r_start + BLOCK_SIZE_R; ++r) {
        for (c = c_start; c < c_start + BLOCK_SIZE_C; ++c) {
            result[r * col + c] = temp[r * col + c] +
                (Cap_1 * (power[r * col + c] +
                (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.f * temp[r * col + c]) * Ry_1 +
                (temp[r * col + c + 1] + temp[r * col + c - 1] - 2.f * temp[r * col + c]) * Rx_1 +
                (amb_temp - temp[r * col + c]) * Rz_1));
        }
    }
}

void single_iteration(FLOAT *result, FLOAT *temp, FLOAT *power, int row, int col,
                      FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1,
                      FLOAT step)
{
    int num_chunk = row * col / (BLOCK_SIZE_R * BLOCK_SIZE_C);
    if (num_chunk <= 0)
        return;

    int threads = 256;
    int blocks = (num_chunk + threads - 1) / threads;
    single_iteration_kernel<<<blocks, threads>>>(result, temp, power, row, col, Cap_1, Rx_1, Ry_1, Rz_1, step);
    cuda_check(cudaGetLastError(), "kernel launch failed");
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col)
{
#ifdef VERBOSE
    int i = 0;
#endif

    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0f;

    FLOAT Rx_1 = 1.f / Rx;
    FLOAT Ry_1 = 1.f / Ry;
    FLOAT Rz_1 = 1.f / Rz;
    FLOAT Cap_1 = step / Cap;
#ifdef VERBOSE
    fprintf(stdout, "total iterations: %d s\tstep size: %g s\n", num_iterations, step);
    fprintf(stdout, "Rx: %g\tRy: %g\tRz: %g\tCap: %g\n", Rx, Ry, Rz, Cap);
#endif

    int array_size = row * col;
    size_t bytes = (size_t)array_size * sizeof(FLOAT);

    FLOAT *d_temp = NULL;
    FLOAT *d_power = NULL;
    FLOAT *d_result = NULL;

    cuda_check(cudaMalloc((void **)&d_temp, bytes), "unable to allocate device memory for temp");
    cuda_check(cudaMalloc((void **)&d_power, bytes), "unable to allocate device memory for power");
    cuda_check(cudaMalloc((void **)&d_result, bytes), "unable to allocate device memory for result");

    cuda_check(cudaMemcpy(d_temp, temp, bytes, cudaMemcpyHostToDevice), "copy temp to device failed");
    cuda_check(cudaMemcpy(d_power, power, bytes, cudaMemcpyHostToDevice), "copy power to device failed");
    cuda_check(cudaMemcpy(d_result, result, bytes, cudaMemcpyHostToDevice), "copy result to device failed");

    FLOAT *r = d_result;
    FLOAT *t = d_temp;
    for (int i = 0; i < num_iterations; i++)
    {
#ifdef VERBOSE
        fprintf(stdout, "iteration %d\n", i++);
#endif
        single_iteration(r, t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1, step);
        FLOAT *tmp = t;
        t = r;
        r = tmp;
    }

    cuda_check(cudaDeviceSynchronize(), "kernel execution failed");
    cuda_check(cudaMemcpy(temp, d_temp, bytes, cudaMemcpyDeviceToHost), "copy temp from device failed");
    cuda_check(cudaMemcpy(result, d_result, bytes, cudaMemcpyDeviceToHost), "copy result from device failed");

    cudaFree(d_temp);
    cudaFree(d_power);
    cudaFree(d_result);

#ifdef VERBOSE
    fprintf(stdout, "iteration %d\n", i++);
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
    exit(1);
}

void writeoutput(FLOAT *vect, int grid_rows, int grid_cols, char *file)
{
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++)
        {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);
}

void read_input(FLOAT *vect, int grid_rows, int grid_cols, char *file)
{
    int i, index;
    FILE *fp;
    char str[STR_SIZE];
    FLOAT val;

    fp = fopen(file, "r");
    if (!fp)
        fatal((char *)"file could not be opened for reading");

    for (i = 0; i < grid_rows * grid_cols; i++) {
        fgets(str, STR_SIZE, fp);
        if (feof(fp))
            fatal((char *)"not enough lines in file");
        if ((sscanf(str, "%f", &val) != 1))
            fatal((char *)"invalid file format");
        vect[i] = val;
    }

    fclose(fp);
}

