{
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    int r = blockIdx.y * blockDim.y + threadIdx.y;

    if (r >= row || c >= col)
        return;

    int idx = r * col + c;
    FLOAT delta;

    if ((r == 0) && (c == 0)) {
        delta = (Cap_1) * (power[0] +
            (temp[1] - temp[0]) * Rx_1 +
