}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col)
{
#ifdef VERBOSE
    int i = 0;
#endif

    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0f;

    FLOAT Rx_1 = 1.0f / Rx;
    FLOAT Ry_1 = 1.0f / Ry;
    FLOAT Rz_1 = 1.0f / Rz;
    FLOAT Cap_1 = step / Cap;

#ifdef VERBOSE
    fprintf(stdout, "total iterations: %d s\tstep size: %g s\n", num_iterations, step);
    fprintf(stdout, "Rx: %g\tRy: %g\tRz: %g\tCap: %g\n", Rx, Ry, Rz, Cap);
#endif

    size_t array_size = (size_t)row * (size_t)col;
    size_t bytes = array_size * sizeof(FLOAT);

    FLOAT *d_temp = NULL;
    FLOAT *d_power = NULL;
    FLOAT *d_result = NULL;

    CUDA_CHECK(cudaMalloc((void **)&d_temp, bytes));
    CUDA_CHECK(cudaMalloc((void **)&d_power, bytes));
    CUDA_CHECK(cudaMalloc((void **)&d_result, bytes));

    CUDA_CHECK(cudaMemcpy(d_temp, temp, bytes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_power, power, bytes, cudaMemcpyHostToDevice));

    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((unsigned int)((col + BLOCK_SIZE_C - 1) / BLOCK_SIZE_C),
              (unsigned int)((row + BLOCK_SIZE_R - 1) / BLOCK_SIZE_R));

    FLOAT *r = d_result;
    FLOAT *t = d_temp;

    for (int iter = 0; iter < num_iterations; iter++) {
#ifdef VERBOSE
        fprintf(stdout, "iteration %d\n", i++);
#endif
        single_iteration_kernel<<<grid, block>>>(r, t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
        CUDA_CHECK(cudaGetLastError());

        FLOAT *tmp = t;
        t = r;
        r = tmp;
    }

    CUDA_CHECK(cudaDeviceSynchronize());

    CUDA_CHECK(cudaMemcpy(temp, d_temp, bytes, cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(result, d_result, bytes, cudaMemcpyDeviceToHost));

    CUDA_CHECK(cudaFree(d_temp));
