    float value = 0.0f;
    while (*s >= '0' && *s <= '9') {
        value = value * 10.0f + (float)(*s - '0');
        s++;
    }

    if (*s == '.') {
        s++;
        float place = 0.1f;
        while (*s >= '0' && *s <= '9') {
            value += (float)(*s - '0') * place;
            place *= 0.1f;
            s++;
        }
    }

    return sign * value;
}

