#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

static __host__ __device__ __forceinline__ int maximum_cuda(int a, int b, int c)
{
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

__global__ void nw_top_left_kernel(int *input_itemsets, const int *referrence,
                                   int max_cols, int penalty, int blk)
{
    if (threadIdx.x != 0 || blockIdx.x >= (unsigned int)blk)
        return;

    int b_index_x = (int)blockIdx.x;
    int b_index_y = blk - 1 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum_cuda(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                        reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_bottom_right_kernel(int *input_itemsets, const int *referrence,
                                       int max_cols, int penalty, int blk, int num_tiles)
{
    if (threadIdx.x != 0)
        return;

    int local_idx = (int)blockIdx.x;
    int b_index_x = blk - 1 + local_idx;
    if (b_index_x >= num_tiles)
        return;

    int b_index_y = num_tiles + blk - 2 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum_cuda(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                        reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
                  int max_rows, int max_cols, int penalty)
{
    (void)output_itemsets;

    size_t transfer_size = (size_t)max_rows * (size_t)max_cols * sizeof(int);
    int *d_input_itemsets = NULL;
    int *d_referrence = NULL;

    cudaMalloc((void **)&d_input_itemsets, transfer_size);
    cudaMalloc((void **)&d_referrence, transfer_size);

    cudaMemcpy(d_input_itemsets, input_itemsets, transfer_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, transfer_size, cudaMemcpyHostToDevice);

    int num_tiles = (max_cols - 1) / BLOCK_SIZE;

    for (int blk = 1; blk <= num_tiles; blk++) {
        nw_top_left_kernel<<<blk, 1>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk);
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= num_tiles; blk++) {
        int active_blocks = num_tiles - (blk - 1);
        nw_bottom_right_kernel<<<active_blocks, 1>>>(
            d_input_itemsets, d_referrence, max_cols, penalty, blk, num_tiles);
    }

    cudaDeviceSynchronize();
    cudaMemcpy(input_itemsets, d_input_itemsets, transfer_size, cudaMemcpyDeviceToHost);

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

