        dE[k] = J[i * cols + jE[j]] - Jc;

        float G2 = (dN[k] * dN[k] + dS[k] * dS[k] +
                    dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);

        float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

        float num = (float)((0.5 * G2) - ((1.0 / 16.0) * (L * L)));
