            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        x_0 = atoi(argv[3]);
        var_1 = atoi(argv[4]);
        tmp_14 = atoi(argv[5]);
        v_17 = atoi(argv[6]);
        var_15 = atoi(argv[7]);
        lambda = (float)atof(argv[8]);
        data_5 = atoi(argv[9]);
    }
    else {
        usage(argc, argv);
    }

    (void)var_15;

    v_13 = cols * rows;
    v_18 = (var_1 - x_0 + 1) * (v_17 - tmp_14 + 1);

    I = (float *)malloc(v_13 * sizeof(float));
    J = (float *)malloc(v_13 * sizeof(float));

    if (I == NULL || J == NULL) {
        fprintf(stderr, "memory allocation error\n");
        free(I);
        free(J);
        return 1;
    }

    CUDA_CHECK(cudaMalloc((void **)&d_J,  v_13 * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_c,  v_13 * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dN, v_13 * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dS, v_13 * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dW, v_13 * sizeof(float)));
    CUDA_CHECK(cudaMalloc((void **)&d_dE, v_13 * sizeof(float)));

    printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (k = 0; v_13 > k; k++) {
        J[k] = expf(I[k]);
    }

    CUDA_CHECK(cudaMemcpy(d_J, J, v_13 * sizeof(float), cudaMemcpyHostToDevice));

    printf("Start the SRAD main loop\n");

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

    for (data_11 = 0; data_5 > data_11; data_11++) {
        elem_16 = 0.0f;
        x_10 = 0.0f;
        for (i = x_0; var_1 >= i; i++) {
            for (j = tmp_14; v_17 >= j; j++) {
                val_7 = J[i * cols + j];
                elem_16 = elem_16 + val_7;
                x_10 = x_10 + (val_7 * val_7);
            }
        }
        x_2 = elem_16 / (float)v_18;
        tmp_12 = (x_10 / (float)v_18) - x_2 * x_2;
        elem_9 = tmp_12 / (x_2 * x_2);

        compute_coeff_kernel<<<grid, block>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c, rows, cols, elem_9);
        CUDA_CHECK(cudaGetLastError());

        update_kernel<<<grid, block>>>(d_J, d_c, d_dN, d_dS, d_dW, d_dE, rows, cols, lambda);
        CUDA_CHECK(cudaGetLastError());

        CUDA_CHECK(cudaMemcpy(J, d_J, v_13 * sizeof(float), cudaMemcpyDeviceToHost));
    }

#ifdef OUTPUT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    free(I);
    free(J);

    CUDA_CHECK(cudaFree(d_J));
    CUDA_CHECK(cudaFree(d_c));
    CUDA_CHECK(cudaFree(d_dN));
    CUDA_CHECK(cudaFree(d_dS));
    CUDA_CHECK(cudaFree(d_dW));
    CUDA_CHECK(cudaFree(d_dE));

    return 0;
}

void random_matrix(float *I, int x_8, int tmp_6)
{
    srand(7);

    for (int i = 0; x_8 > i; i++) {
        for (int j = 0; tmp_6 > j; j++) {
            I[i * tmp_6 + j] = rand() / (float)RAND_MAX;
#ifdef OUTPUT
#endif
        }
#ifdef OUTPUT
#endif
    }
}
